import base64
import json
import os

from google.cloud import firestore
from google.cloud import pubsub_v1
from google.cloud import storage

def process_gcs_file(event, context):
    """Triggered by a change to a Cloud Storage bucket.
    Args:
         event (dict): Event payload.
         context (google.cloud.functions.Context): Metadata for the event.
    """
    
    # Configuration
    FIRESTORE_COLLECTION_NAME = os.environ.get('FIRESTORE_COLLECTION_NAME', 'gcs_processed_files')
    PUBSUB_TOPIC_NAME = os.environ.get('PUBSUB_TOPIC_NAME', 'gcs_file_processing_topic')
    PROJECT_ID = os.environ.get('GCP_PROJECT') # Automatically available in GCF

    if not PROJECT_ID:
        raise ValueError("GCP_PROJECT environment variable not set. This should be automatically set in GCF.")
    
    if not event or not event.get('bucket') or not event.get('name'):
        print(f"Invalid event payload: {event}")
        return

    bucket_name = event['bucket']
    file_name = event['name']
    file_uri = f"gs://{bucket_name}/{file_name}"
    
    print(f"Processing file: {file_uri}")

    # Initialize Google Cloud clients
    storage_client = storage.Client()
    firestore_client = firestore.Client()
    publisher = pubsub_v1.PublisherClient()
    pubsub_topic_path = publisher.topic_path(PROJECT_ID, PUBSUB_TOPIC_NAME)

    try:
        # 1. Read file from Cloud Storage
        bucket = storage_client.bucket(bucket_name)
        blob = bucket.blob(file_name)
        
        # Download the file content
        file_content = blob.download_as_text()
        print(f"Successfully read file {file_name} from GCS. Content length: {len(file_content)} bytes.")

        # Prepare data for Firestore and Pub/Sub
        processing_data = {
            "bucket": bucket_name,
            "file_name": file_name,
            "file_uri": file_uri,
            "size": event.get('size'),
            "contentType": event.get('contentType'),
            "timeCreated": event.get('timeCreated'),
            "updated": event.get('updated'),
            "file_content_sample": file_content[:500] + "..." if len(file_content) > 500 else file_content, # Store a sample
            "processed_at": firestore.SERVER_TIMESTAMP
        }

        # 2. Write record to Firestore
        doc_ref = firestore_client.collection(FIRESTORE_COLLECTION_NAME).document(file_name.replace('.', '_'))
        doc_ref.set(processing_data)
        print(f"Successfully wrote data to Firestore document: {doc_ref.path}")

        # 3. Publish message to Pub/Sub
        # Ensure the message is JSON serializable and then encoded
        pubsub_message_data = {
            "action": "gcs_file_processed",
            "file_uri": file_uri,
            "firestore_document_path": doc_ref.path,
            "bucket_name": bucket_name,
            "file_name": file_name,
            "timeCreated": event.get('timeCreated'),
            "processed_at": firestore.SERVER_TIMESTAMP # Will be converted to datetime object by client library
        }
        
        # Pub/Sub message data must be bytes
        data_bytes = json.dumps(pubsub_message_data).encode("utf-8")
        
        # Publish the message
        future = publisher.publish(pubsub_topic_path, data_bytes)
        message_id = future.result()
        print(f"Published message with ID {message_id} to Pub/Sub topic: {PUBSUB_TOPIC_NAME}")

    except Exception as e:
        print(f"Error processing file {file_uri}: {e}")
        # Depending on requirements, you might re-raise the exception or log it to a specific system
        raise e

